svg.script:
(function(){
  var NS = "http://www.w3.org/2000/svg";
  var svg = (document.documentElement.tagName.toLowerCase()==="svg") ? document.documentElement : document.querySelector("svg");
  var tt  = svg.getElementById("tt");
  var bg  = svg.getElementById("tt-bg");
  var txt = svg.getElementById("tt-text");
  var dataLayer = svg.getElementById("data-layer");
  var xAxis = svg.getElementById("x-axis");
  var yAxis = svg.getElementById("y-axis");
  var zoomBox = svg.getElementById("zoom-box");
  var resetBtn = svg.getElementById("reset-btn");
  var legendNber  = svg.getElementById("legend-nber");
  var legendModel = svg.getElementById("legend-model");
  var pad = 10, lh = 16;
  var mL=80, mT=80, pW=610, pH=380;
  var XMIN=0, XMAX=1, YMIN=50, YMAX=130;
  var MAX_ZOOM = 8;
  var state = { tx: 0, ty: 0, s: 1 };

  function clearChildren(el){ while(el.firstChild) el.removeChild(el.firstChild); }
  function addLine(parent, cls, x1, y1, x2, y2){
    var ln = document.createElementNS(NS, "line");
    ln.setAttribute("class", cls);
    ln.setAttribute("x1", x1); ln.setAttribute("y1", y1);
    ln.setAttribute("x2", x2); ln.setAttribute("y2", y2);
    parent.appendChild(ln);
  }
  function addText(parent, cls, x, y, content, anchor){
    var t = document.createElementNS(NS, "text");
    t.setAttribute("class", cls);
    t.setAttribute("x", x); t.setAttribute("y", y);
    if (anchor) t.setAttribute("text-anchor", anchor);
    t.textContent = content;
    parent.appendChild(t);
  }

  function dataXtoSvg(v){ return mL + (v - XMIN)/(XMAX - XMIN) * pW; }
  function dataYtoSvg(v){ return mT + pH - (v - YMIN)/(YMAX - YMIN) * pH; }
  function svgXtoData(u){ return XMIN + (u - mL)/pW * (XMAX - XMIN); }
  function svgYtoData(u){ return YMIN + (mT + pH - u)/pH * (YMAX - YMIN); }

  function visibleRange(){
    var uxmin = (mL - state.tx)/state.s;
    var uxmax = (mL + pW - state.tx)/state.s;
    var uytop = (mT - state.ty)/state.s;
    var uybot = (mT + pH - state.ty)/state.s;
    return { dxmin: svgXtoData(uxmin), dxmax: svgXtoData(uxmax),
             dymax: svgYtoData(uytop), dymin: svgYtoData(uybot) };
  }

  function niceTicks(min, max, target){
    target = target || 8;
    var range = max - min;
    if (range <= 0) return [];
    var rough = range/target;
    var mag = Math.pow(10, Math.floor(Math.log(rough)/Math.LN10));
    var res = rough/mag;
    var step = (res<1.5?1:res<3?2:res<7?5:10) * mag;
    var start = Math.ceil(min/step) * step;
    var out = [];
    for (var v=start; v<=max + step*1e-6; v+=step){ out.push(Math.round(v/step)*step); }
    return out;
  }
  function formatTick(v, step){
    var dec = Math.max(0, -Math.floor(Math.log(step)/Math.LN10 - 1e-9));
    return v.toFixed(dec);
  }

  function redrawAxes(){
    var vr = visibleRange();
    clearChildren(xAxis);
    var xt = niceTicks(vr.dxmin, vr.dxmax, 8);
    var xstep = xt.length>1 ? (xt[1]-xt[0]) : 0.1;
    xt.forEach(function(v){
      var sxv = state.tx + state.s * dataXtoSvg(v);
      if (sxv < mL - 1 || sxv > mL + pW + 1) return;
      addLine(xAxis, "gridline", sxv, mT, sxv, mT + pH);
      addLine(xAxis, "axis-tick", sxv, mT + pH, sxv, mT + pH + 5);
      addText(xAxis, "tick-label", sxv, mT + pH + 19, formatTick(v, xstep), "middle");
    });
    clearChildren(yAxis);
    var yt = niceTicks(vr.dymin, vr.dymax, 8);
    var ystep = yt.length>1 ? (yt[1]-yt[0]) : 5;
    yt.forEach(function(v){
      var syv = state.ty + state.s * dataYtoSvg(v);
      if (syv < mT - 1 || syv > mT + pH + 1) return;
      addLine(yAxis, "gridline", mL, syv, mL + pW, syv);
      addLine(yAxis, "axis-tick", mL - 5, syv, mL, syv);
      addText(yAxis, "tick-label", mL - 9, syv + 4, formatTick(v, ystep), "end");
    });
  }

  function applyTransform(){
    dataLayer.setAttribute("transform", "translate("+state.tx+","+state.ty+") scale("+state.s+")");
    redrawAxes();
    var idle = (state.s===1 && state.tx===0 && state.ty===0);
    resetBtn.style.display = idle ? "none" : "";
  }
  function clampPan(){
    if (state.s > 1){
      var lox = (mL + pW)*(1 - state.s), hix = mL*(1 - state.s);
      if (state.tx < lox) state.tx = lox;
      if (state.tx > hix) state.tx = hix;
      var loy = (mT + pH)*(1 - state.s), hiy = mT*(1 - state.s);
      if (state.ty < loy) state.ty = loy;
      if (state.ty > hiy) state.ty = hiy;
    } else { state.tx = 0; state.ty = 0; state.s = 1; }
  }
  function reset(){ state.tx = 0; state.ty = 0; state.s = 1; applyTransform(); }
  function zoomAt(svgX, svgY, f){
    var newS = state.s * f;
    if (newS < 1){ reset(); return; }
    if (newS > MAX_ZOOM){ f = MAX_ZOOM/state.s; newS = MAX_ZOOM; }
    state.tx = svgX*(1 - f) + state.tx*f;
    state.ty = svgY*(1 - f) + state.ty*f;
    state.s = newS;
    clampPan(); applyTransform();
  }

  function clientToSvg(e){
    var pt = svg.createSVGPoint(); pt.x = e.clientX; pt.y = e.clientY;
    var p = pt.matrixTransform(svg.getScreenCTM().inverse());
    return { x: p.x, y: p.y };
  }
  function inPlot(p){ return p.x>=mL && p.x<=mL+pW && p.y>=mT && p.y<=mT+pH; }

  function diamondPoints(cx, cy, r){
    return cx+","+(cy-r)+" "+(cx+r)+","+cy+" "+cx+","+(cy+r)+" "+(cx-r)+","+cy;
  }
  function trianglePoints(cx, cy, r){
    var k = r * 0.866;
    return cx+","+(cy-r)+" "+(cx+k)+","+(cy+r*0.5)+" "+(cx-k)+","+(cy+r*0.5);
  }
  function setMarkerSize(c, r){
    if (c.classList.contains("diamond")){
      var cx = parseFloat(c.getAttribute("data-cx"));
      var cy = parseFloat(c.getAttribute("data-cy"));
      c.setAttribute("points", diamondPoints(cx, cy, r));
    } else if (c.classList.contains("triangle")){
      var cx2 = parseFloat(c.getAttribute("data-cx"));
      var cy2 = parseFloat(c.getAttribute("data-cy"));
      c.setAttribute("points", trianglePoints(cx2, cy2, r));
    } else {
      c.setAttribute("r", r);
    }
  }
  function show(e){
    var c = e.currentTarget;
    var lines = (c.getAttribute("data-tip")||"").split("|");
    var isLatest = c.classList.contains("latest");
    clearChildren(txt);
    lines.forEach(function(ln,i){
      var ts = document.createElementNS(NS, "tspan");
      ts.setAttribute("x", pad); ts.setAttribute("dy", lh);
      if (i===0 && isLatest) ts.setAttribute("class","tt-bold");
      ts.textContent = ln;
      txt.appendChild(ts);
    });
    tt.style.visibility = "visible";
    var b = txt.getBBox();
    var w = Math.ceil(b.width + 2*pad);
    var h = Math.ceil(lh*lines.length + pad);
    bg.setAttribute("x", 0); bg.setAttribute("y", 0);
    bg.setAttribute("width", w); bg.setAttribute("height", h);
    var cx = parseFloat(c.getAttribute("data-cx"));
    var cy = parseFloat(c.getAttribute("data-cy"));
    if (dataLayer.contains(c)){ cx = state.tx + state.s*cx; cy = state.ty + state.s*cy; }
    var vb = svg.viewBox.baseVal;
    var x = cx + 12, y = cy - h - 12;
    if (x + w > vb.width - 4) x = cx - w - 12;
    if (y < 4) y = cy + 12;
    tt.setAttribute("transform","translate("+x+","+y+")");
    var r0 = parseFloat(c.getAttribute("data-r"));
    setMarkerSize(c, r0 + 2);
  }
  function hide(e){
    tt.style.visibility = "hidden";
    var c = e.currentTarget;
    var r0 = parseFloat(c.getAttribute("data-r"));
    if (!isNaN(r0)) setMarkerSize(c, r0);
  }
  svg.querySelectorAll(".point").forEach(function(p){
    p.addEventListener("mouseenter", show);
    p.addEventListener("mouseleave", hide);
  });

  svg.querySelectorAll(".legend-item").forEach(function(item){
    item.addEventListener("click", function(){
      var cat = item.getAttribute("data-cat");
      var grp = svg.querySelector('g.cat[data-cat="'+cat+'"]');
      item.classList.toggle("dimmed");
      if (grp) grp.classList.toggle("dimmed");
    });
  });

  var currentMode    = "nber";
  var currentHorizon = 1;
  function applyAll(){
    svg.querySelectorAll(".point").forEach(function(c){
      var f = c.getAttribute("data-fill-"+currentMode);
      if (f) c.setAttribute("fill", f);
      if (c.classList.contains("latest")){
        var rank = parseInt(c.getAttribute("data-rank"),10);
        if (rank <= currentHorizon){
          c.setAttribute("stroke", "#000000");
          c.setAttribute("stroke-width", "1.4");
        } else {
          var s = c.getAttribute("data-stroke-"+currentMode);
          if (s) c.setAttribute("stroke", s);
          c.setAttribute("stroke-width", "0.8");
        }
      } else {
        var s2 = c.getAttribute("data-stroke-"+currentMode);
        if (s2) c.setAttribute("stroke", s2);
      }
    });
    svg.querySelectorAll(".horizon-btn").forEach(function(b){
      if (parseInt(b.getAttribute("data-horizon"),10)===currentHorizon) b.classList.add("active");
      else b.classList.remove("active");
    });
    svg.querySelectorAll(".mode-btn").forEach(function(b){
      if (b.getAttribute("data-mode")===currentMode) b.classList.add("active");
      else b.classList.remove("active");
    });
    if (legendNber)  legendNber.style.display  = (currentMode==="nber")  ? "" : "none";
    if (legendModel) legendModel.style.display = (currentMode==="model") ? "" : "none";
    if (currentMode==="model"){
      svg.querySelectorAll("g.cat.dimmed").forEach(function(g){ g.classList.remove("dimmed"); });
      svg.querySelectorAll(".legend-item.dimmed").forEach(function(g){ g.classList.remove("dimmed"); });
    }
  }
  function setHorizon(h){ currentHorizon = h; applyAll(); }
  function setMode(mode){ currentMode = mode; applyAll(); }
  svg.querySelectorAll(".horizon-btn").forEach(function(b){
    b.addEventListener("click", function(){
      setHorizon(parseInt(b.getAttribute("data-horizon"),10));
    });
  });

  var drag = null;
  svg.addEventListener("mousedown", function(e){
    if (e.button !== 0) return;
    var p = clientToSvg(e); if (!inPlot(p)) return;
    if (e.shiftKey){
      drag = { mode:"box", x0: p.x, y0: p.y, x1: p.x, y1: p.y };
      zoomBox.setAttribute("x", p.x); zoomBox.setAttribute("y", p.y);
      zoomBox.setAttribute("width", 0); zoomBox.setAttribute("height", 0);
      zoomBox.style.display = "";
    } else {
      drag = { mode:"pan", x0: p.x, y0: p.y, tx0: state.tx, ty0: state.ty };
    }
    e.preventDefault();
  });
  svg.addEventListener("mousemove", function(e){
    if (!drag) return;
    var p = clientToSvg(e);
    p.x = Math.max(mL, Math.min(mL+pW, p.x));
    p.y = Math.max(mT, Math.min(mT+pH, p.y));
    if (drag.mode === "box"){
      drag.x1 = p.x; drag.y1 = p.y;
      var x = Math.min(drag.x0, drag.x1), y = Math.min(drag.y0, drag.y1);
      var w = Math.abs(drag.x1 - drag.x0), h = Math.abs(drag.y1 - drag.y0);
      zoomBox.setAttribute("x", x); zoomBox.setAttribute("y", y);
      zoomBox.setAttribute("width", w); zoomBox.setAttribute("height", h);
    } else if (drag.mode === "pan"){
      state.tx = drag.tx0 + (p.x - drag.x0);
      state.ty = drag.ty0 + (p.y - drag.y0);
      clampPan(); applyTransform();
    }
  });
  function endDrag(){
    if (!drag) return;
    if (drag.mode === "box"){
      zoomBox.style.display = "none";
      var w = Math.abs(drag.x1 - drag.x0), h = Math.abs(drag.y1 - drag.y0);
      if (w > 8 && h > 8){
        var bx = Math.min(drag.x0, drag.x1), by = Math.min(drag.y0, drag.y1);
        var sFactor = Math.min(pW/w, pH/h);
        var newS = state.s * sFactor;
        if (newS > MAX_ZOOM){ newS = MAX_ZOOM; }
        var bcx = bx + w/2, bcy = by + h/2;
        var dcx = (bcx - state.tx)/state.s;
        var dcy = (bcy - state.ty)/state.s;
        state.tx = (mL + pW/2) - newS * dcx;
        state.ty = (mT + pH/2) - newS * dcy;
        state.s = newS;
        clampPan(); applyTransform();
      }
    }
    drag = null;
  }
  svg.addEventListener("mouseup", endDrag);
  svg.addEventListener("mouseleave", endDrag);
  svg.addEventListener("wheel", function(e){
    var p = clientToSvg(e); if (!inPlot(p)) return;
    e.preventDefault();
    var factor = Math.pow(1.0015, -e.deltaY);
    zoomAt(p.x, p.y, factor);
  }, { passive: false });
  svg.addEventListener("dblclick", function(e){
    var p = clientToSvg(e); if (!inPlot(p)) return;
    reset();
  });
  resetBtn.addEventListener("click", reset);

  svg.querySelectorAll(".mode-btn").forEach(function(b){
    b.addEventListener("click", function(){
      setMode(b.getAttribute("data-mode"));
    });
  });

  applyAll();
  redrawAxes();
})();
